command:
/**
 * This macro awards a Fortune point in addition to an Advancement Point, as per the rules
 * for when a GM awards a Fortune point during gameplay on page 61.
 */

const actors = new Set(canvas.tokens.controlled.map(t => t.actor).filter(a => a.type === 'hero'));

if (actors.size === 0) return ui.notifications.warn('HONOR_INTRIGUE.Dialog.Result.NoHeroesSelected', { localize: true });

const fields = foundry.applications.fields;
const proceed = await foundry.applications.api.DialogV2.prompt({
  window: { title: 'HONOR_INTRIGUE.Dialog.AwardFortune.Title' },
  content: game.i18n.localize('HONOR_INTRIGUE.Dialog.AwardFortune.Prompt')
});

if (proceed) {
  await Promise.all(actors.map(async (actor) => actor.update({
    'system.advancementPoints.value': actor.system.advancementPoints.value + 1,
    'system.fortune': actor.system.fortune + 1,
  })));
}
